const webhookData = $('Webhook: Conversation Turn').item.json;
const lead = $('DB: Load Lead Profile').item.json;
const callLog = $('DB: Load Call Log').item.json;

const existingTranscript = callLog.transcript || '[]';
let conversationHistory;
try { conversationHistory = JSON.parse(existingTranscript); } catch(e) { conversationHistory = []; }

conversationHistory.push({ role: 'user', content: webhookData.transcript });

const systemPrompt = `You are Alex, an expert sales consultant for a high-end consulting firm.
Your goal is to qualify ${lead.name || 'this lead'} and book a free 30-minute strategy call.

LEAD PROFILE:
- Name: ${lead.name || 'Unknown'}
- Company: ${lead.company || 'Unknown'}
- Status: ${lead.status}
- Budget: ${lead.budget || 'not discussed'}
- Business size: ${lead.business_size || 'not discussed'}
- Problem: ${lead.problem || 'not discussed'}
- Urgency: ${lead.urgency || 'unknown'}
- Score: ${lead.score}/100

CONVERSATION FLOW: Greeting → Discovery → Qualification → Value Prop → Objection Handling → Book CTA

SPECIAL COMMANDS (append to your response when applicable):
[BOOK_MEETING] - lead agrees to book
[NOT_INTERESTED] - clearly declines after 2 attempts
[ESCALATE] - complex enterprise/legal query
[FOLLOW_UP] - lead asks to be called back

RULES: Max 35 words per response. No filler phrases. Natural voice tone.
Never invent pricing. If asked: starting from $2,500/month.
Current turn: ${webhookData.turn_number} | Duration: ${webhookData.call_duration_so_far}s`;

return [{
  json: {
    system_prompt: systemPrompt,
    conversation_history: conversationHistory,
    lead_id: lead.id,
    call_sid: webhookData.call_sid
  }
}];

const aiText = $json.choices[0].message.content;
const buildCtx = $('Build LLM Context').item.json;

let intent = 'CONTINUE';
let cleanText = aiText;

if (aiText.includes('[BOOK_MEETING]'))    { intent = 'BOOK_MEETING';    cleanText = aiText.replace('[BOOK_MEETING]', '').trim(); }
else if (aiText.includes('[NOT_INTERESTED]')) { intent = 'NOT_INTERESTED'; cleanText = aiText.replace('[NOT_INTERESTED]', '').trim(); }
else if (aiText.includes('[ESCALATE]'))   { intent = 'ESCALATE';       cleanText = aiText.replace('[ESCALATE]', '').trim(); }
else if (aiText.includes('[FOLLOW_UP]'))  { intent = 'FOLLOW_UP';      cleanText = aiText.replace('[FOLLOW_UP]', '').trim(); }

const userMsg = (buildCtx.conversation_history.slice(-1)[0]?.content || '').toLowerCase();
const positive = ['interested','yes','great','definitely','sounds good','perfect','let\'s do it'];
const negative = ['not interested','no thanks','stop','remove','don\'t call','busy'];
let sentiment = 'neutral';
if (positive.some(w => userMsg.includes(w))) sentiment = 'positive';
if (negative.some(w => userMsg.includes(w))) sentiment = 'negative';

const updatedHistory = [...buildCtx.conversation_history, { role: 'assistant', content: cleanText }];

return [{ json: { ai_response_text: cleanText, intent, sentiment, conversation_history: updatedHistory, lead_id: buildCtx.lead_id, call_sid: buildCtx.call_sid } }];

const parseData = $('Parse AI Response').item.json;
const allText = parseData.conversation_history.map(h => h.content).join(' ').toLowerCase();
let score = 0;
if (allText.includes('100k') || allText.includes('100,000')) score += 30;
else if (allText.includes('50k')) score += 22;
else if (allText.includes('25k')) score += 15;
else if (allText.includes('10k')) score += 8;
else if (allText.includes('5k'))  score += 4;
if (allText.includes('asap') || allText.includes('urgent')) score += 25;
else if (allText.includes('this month') || allText.includes('soon')) score += 15;
else if (allText.includes('next quarter')) score += 5;
if (allText.includes('enterprise') || allText.includes('corporation')) score += 20;
else if (allText.includes('team') || allText.includes('50 employees')) score += 10;
if (parseData.sentiment === 'positive') score += 15;
if (parseData.intent === 'BOOK_MEETING') score += 10;
const finalScore = Math.min(score, 100);
let status = finalScore >= 70 ? 'hot' : finalScore >= 40 ? 'warm' : 'cold';
return [{ json: { lead_id: parseData.lead_id, score: finalScore, status } }];
